# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch, NotFoundError
import os
import time
from functools import lru_cache

app = Flask(__name__)

ELASTICSEARCH_URL = os.getenv("ELASTICSEARCH_URL", "http://localhost:9200")
ELASTICSEARCH_INDEX = os.getenv("ELASTICSEARCH_INDEX", "products")
ELASTICSEARCH_API_KEY = os.getenv("ELASTICSEARCH_API_KEY")

es_kwargs = {"hosts": [ELASTICSEARCH_URL], "request_timeout": 2, "max_retries": 3, "retry_on_timeout": True}
if ELASTICSEARCH_API_KEY:
    es_kwargs["api_key"] = ELASTICSEARCH_API_KEY

es = Elasticsearch(**es_kwargs)


@lru_cache(maxsize=2048)
def _cached_search(q: str):
    body = {
        "size": 20,
        "track_total_hits": False,
        "query": {
            "multi_match": {
                "query": q,
                "fields": ["name^3", "brand^2", "description", "category^2", "sku"],
                "type": "best_fields",
                "fuzziness": "AUTO"
            }
        },
        "_source": ["id", "name", "brand", "price", "image", "category", "sku"]
    }
    return es.search(index=ELASTICSEARCH_INDEX, body=body)


@app.route("/api/search", methods=["GET"])
def search_products():
    q = request.args.get("q", "").strip()
    if not q:
        return jsonify({"error": "Missing required query parameter: q"}), 400

    try:
        start = time.time()
        response = _cached_search(q)
        hits = response.get("hits", {}).get("hits", [])
        products = []
        for hit in hits:
            source = hit.get("_source", {})
            source["score"] = hit.get("_score")
            products.append(source)

        return jsonify({
            "query": q,
            "count": len(products),
            "products": products,
            "took_ms": int((time.time() - start) * 1000)
        }), 200
    except NotFoundError:
        return jsonify({"error": "Search index not found"}), 500
    except Exception:
        return jsonify({"error": "Search service unavailable"}), 503


@app.route("/health", methods=["GET"])
def health():
    try:
        es.ping(request_timeout=1)
        return jsonify({"status": "ok"}), 200
    except Exception:
        return jsonify({"status": "degraded"}), 503


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.getenv("PORT", "5000")), threaded=True)